  /**
   * Conversation this session is bound to, when one exists. Nullable
   * because not every session is conversation-scoped (canary acceptance
   * tests, ephemeral admin probes, pre-Task-15 sessions). The runner uses
   * this to decide whether to call `conversation.fetch-history` at boot.
   *
   * The host populates this from the session row (Task 15 added a
   * `conversation_id` column to the session backend; the orchestrator
   * sets it at session-creation time). NEVER `undefined` — explicit null
   * keeps the wire shape stable across the schema bump (an absent field
   * would force every consumer to branch on three states).
   */
  conversationId: z.string().nullable(),
});
export type SessionGetConfigResponse = z.infer<typeof SessionGetConfigResponseSchema>;

// ---------------------------------------------------------------------------
// conversation.fetch-history
//
// Runner → host RPC fetched at boot AFTER `session.get-config` returns a
// non-null conversationId. Returns the persisted turn-by-turn transcript
// so the runner can replay user-side history into the SDK's prompt
// iterator before processing live inbox messages (J3 + J6 resume).
//
// Authz on the host: the bus-side `conversations:fetch-history` hook calls
// `conversations:get(conversationId, ctx.userId)` — that gate already
// enforces user ownership AND `agents:resolve`, so a runner that forges a
// foreign conversationId still can't read it. The runner authenticates
// IPC via its session bearer token; the IPC server resolves the token
// to ctx.userId, and that userId is what reaches `conversations:get`.
//
// Field-name conventions (I1):
//   - `turns` is generic. Each entry is `{ role, contentBlocks }` — same
//     shape Anthropic / OpenAI / Gemini wrappers translate into. No
//     storage-backend vocabulary leaks.
//   - We deliberately do NOT include turnId / createdAt / turnIndex on
//     the wire shape. The runner replays into the SDK; ordering is
//     implicit in the array order, and identity is the LLM's concern,
//     not ours. A future audit/debug consumer that wants those fields
//     should call `conversations:get` directly (host-side hook).
// ---------------------------------------------------------------------------

export const ConversationFetchHistoryRequestSchema = z.object({
  conversationId: z.string().min(1).max(256),
}).strict();
export type ConversationFetchHistoryRequest = z.infer<
  typeof ConversationFetchHistoryRequestSchema
>;

export const ConversationFetchHistoryTurnSchema = z.object({
  role: z.enum(['user', 'assistant', 'tool']),
  contentBlocks: z.array(ContentBlockSchema),
});
export type ConversationFetchHistoryTurn = z.infer<
  typeof ConversationFetchHistoryTurnSchema
>;

/**
 * Per-action timeout ceilings for host-side RPC dispatch (milliseconds).
 *
 * Frozen at module load so callers can't mutate them at runtime. Body-size
 * policing lives elsewhere (see `@ax/core/src/ipc/framing.ts` `MAX_FRAME`,
 * 4 MiB) — this map is strictly about how long a single in-flight RPC is
 * allowed to take.
 *
 * The keyset is the authoritative list of sandbox→host action names.
 */
export const IPC_TIMEOUTS_MS = Object.freeze({
  'tool.pre-call': 10_000,
  'tool.execute-host': 30_000,
  'tool.list': 5_000,
  'workspace.commit-notify': 30_000,
  // Phase 3: session-start materialize fires once at boot. The host
  // builds a baseline bundle by walking workspace:list + workspace:read,
  // so the cost scales with workspace size. 30 s gives even chunky
  // workspaces room without forcing per-file streaming on the wire.
  'workspace.materialize': 30_000,
  'session.next-message': 30_000,
  // Runner-boot config fetch. Synchronous, small payload (a few KiB at
  // most). 5 s is generous; if the host can't answer this fast something
  // bigger is wrong and the runner should fail-fast rather than retry.
  'session.get-config': 5_000,
  // Runner-boot history replay (Task 15 of Week 10–12). Reads turns rows
  // for the bound conversation; the host's `conversations:get` already
  // bounds the row count via storage limits. 30 s gives a long
  // conversation room to deserialize without us needing per-turn
  // streaming on this RPC.
  'conversation.fetch-history': 30_000,
});

/** The closed set of sandbox→host RPC action names. */
export type IpcActionName = keyof typeof IPC_TIMEOUTS_MS;

// @ax/core has a MAX_FRAME of 4 MiB, but this package must not import the
// kernel (sandbox-side), so we redeclare the same ceiling here. We may
// unify if that boundary shifts.
// ---------------------------------------------------------------------------

const MAX_RESPONSE_BYTES = 4 * 1024 * 1024;

// Dispatch table: action → Zod schema for the successful response body.
// Event endpoints have no response body (just {accepted: true} on 202) and
// are handled separately in `event()`.
const RESPONSE_SCHEMAS: Record<IpcActionName, z.ZodTypeAny> = {
  'tool.pre-call': ToolPreCallResponseSchema,
  'tool.execute-host': ToolExecuteHostResponseSchema,
  'tool.list': ToolListResponseSchema,
  'workspace.commit-notify': WorkspaceCommitNotifyResponseSchema,
  'workspace.materialize': WorkspaceMaterializeResponseSchema,
  'session.next-message': SessionNextMessageResponseSchema,
  'session.get-config': SessionGetConfigResponseSchema,
  'conversation.fetch-history': ConversationFetchHistoryResponseSchema,
};

export interface IpcClientOptions {
  /**
   * Opaque URI the runner uses to reach the host. Schemes:
   *   - `unix:///abs/path` — connects to a Unix domain socket at the path.
   *   - `http://host:port` — TCP HTTP to the host's IPC listener.
   *
   * The runner doesn't pick the scheme — the sandbox provider does, and
   * sets AX_RUNNER_ENDPOINT in the runner's env. See @ax/sandbox-subprocess
   * (`unix://`) and @ax/sandbox-k8s (`http://`).
   */
  runnerEndpoint: string;
  token: string;
  /** Defaults from @ax/ipc-protocol IPC_TIMEOUTS_MS. Tests override. */
  timeouts?: Partial<Record<IpcActionName, number>>;
  /** Defaults to an exponential-backoff schedule (100 → 30_000 ms cap). */
  retryBackoff?: (attempt: number) => number;
  /** Max retry attempts on connection-level errors / 5xx. Default: 5. */
  maxRetries?: number;
  /** Testable seam. */

