113	function isErr(r: HandlerResult): r is HandlerErr {
114	  // An OK body is whatever the handler returned; the error body has the
115	  // { error: { code, message } } envelope. We treat any result with that
116	  // envelope as an error so the dispatcher writes via writeJsonError and
117	  // the logger stays at the right level.
118	  const body = (r as HandlerOk).body as { error?: unknown } | undefined;
119	  return (
120	    body !== undefined &&
121	    body !== null &&
122	    typeof body === 'object' &&
123	    'error' in body &&
124	    typeof (body as { error: unknown }).error === 'object'
125	  );
126	}
