32	import { createPreToolUseHook } from './pre-tool-use.js';
33	import { setupProxy } from './proxy-startup.js';
34	import { DISABLED_BUILTINS, MCP_HOST_SERVER_NAME } from './tool-names.js';
35	
36	// ---------------------------------------------------------------------------
37	// Runner entry binary (claude-sdk variant).
38	//
39	// Spawned as a child process by a `sandbox:open-session` impl inside an
40	// isolated sandbox. Communicates back to the host over the URI in
41	// AX_RUNNER_ENDPOINT (unix:// today, http:// once Task 14 lands), authed
42	// with AX_AUTH_TOKEN.
43	//
44	// The runner holds NO LLM credentials (invariant I5). The vendored
45	// @anthropic-ai/claude-agent-sdk calls api.anthropic.com through the
46	// host-side credential-proxy (see proxy-startup.ts); the SDK's outbound
47	// x-api-key carries an `ax-cred:<hex>` placeholder that the proxy
48	// substitutes for the real Anthropic key mid-flight. If the sandbox is
49	// compromised, the real key never entered this process.
50	//
51	// Shape: one persistent `query()` driven by an async generator that pulls
52	// user messages from the inbox long-poll. That keeps a single SDK session
53	// alive for the life of the runner instead of spawning a fresh one per
54	// chat turn — the SDK's internal conversation history carries across
55	// turns automatically.
56	//
57	// Exit codes (the spawning host branches on these):
58	//   0 — chat completed normally (inbox returned cancel; SDK drained).
59	//   1 — terminated abnormally (SDK threw, IPC errored after retries, etc.).
60	//   2 — fatal during bootstrap (missing env, initial tool.list failure).
61	//
62	// Boot-failure paths (return 2 before the IPC client is built, or before
63	// the SDK iterator starts) exit WITHOUT firing `event.chat-end`. That's
64	// fine — the orchestrator's `handle.exited` watcher synthesizes a
65	// terminated outcome with reason `sandbox-exit-before-chat-end`, so
66	// chat:end still fires exactly once per agent:invoke from a subscriber's
67	// perspective.
68	// ---------------------------------------------------------------------------
69	
70	export async function main(): Promise<number> {
71	  let env;
72	  try {
73	    env = readRunnerEnv();
74	  } catch (err) {
75	    process.stderr.write(
76	      `runner: ${err instanceof Error ? err.message : String(err)}\n`,
77	    );
78	    return 2;
79	  }
80	
81	  // Start the credential-proxy bridge if AX_PROXY_UNIX_SOCKET is set
82	  // (k8s sandbox); rewrite process.env.HTTP(S)_PROXY in-process so the
83	  // SDK's outbound fetch sees the loopback bridge. Direct mode
84	  // (AX_PROXY_ENDPOINT) is a no-op here — sandbox-subprocess already set
85	  // HTTPS_PROXY in the child env.
86	  let proxyStartup: Awaited<ReturnType<typeof setupProxy>>;
87	  try {
88	    proxyStartup = await setupProxy(env);
89	  } catch (err) {
90	    process.stderr.write(
91	      `runner: proxy setup failed: ${err instanceof Error ? err.message : String(err)}\n`,
92	    );
93	    return 2;
94	  }
95	
96	  const client = createIpcClient({
97	    runnerEndpoint: env.runnerEndpoint,
98	    token: env.authToken,
99	  });
100	
101	  // Week 9.5: fetch the frozen agent config the orchestrator wrote when it
102	  // resolved this session's agent. We do this BEFORE tool.list so we can
103	  // filter the catalog defensively against `allowedTools` even if the
104	  // host's tool-dispatcher (Task 7) hasn't filtered yet.
105	  //
106	  // The bearer token in env.authToken is the SAME token the host used to
107	  // mint this session — the IPC server resolves it to ctx.sessionId, and
108	  // the session backend reads its own row keyed by that. There's no
109	  // sessionId on the wire; the runner cannot ask for someone else's
110	  // config.
111	  let agentConfig: SessionGetConfigResponse['agentConfig'];
112	  let conversationId: string | null = null;
113	  try {
114	    const cfg = (await client.call(
115	      'session.get-config',
116	      {},
117	    )) as SessionGetConfigResponse;
118	    agentConfig = cfg.agentConfig;
119	    // Task 15 (Week 10–12): the host populates conversationId at session-
120	    // creation time when the runner is for an existing conversation. The
121	    // runner uses a truthy value as the trigger to fetch transcript
122	    // history and replay it into the SDK's prompt iterator (J3 + J6
123	    // resume). We normalize `undefined` (older host that hasn't shipped
124	    // the field) and `null` (non-conversation session) into the same
125	    // skip-replay branch via a strict equality check on the string type
126	    // — anything else takes the fetch path.
127	    conversationId = typeof cfg.conversationId === 'string' ? cfg.conversationId : null;
128	  } catch (err) {
129	    process.stderr.write(
130	      `runner: session.get-config failed: ${err instanceof Error ? err.message : String(err)}\n`,
131	    );
132	    await client.close();
133	    return 2;
134	  }
135	
136	  // Phase 3: materialize /permanent from a host-streamed baseline bundle
137	  // BEFORE the SDK query opens. Failure here is bootstrap-fatal — the
138	  // runner has nowhere to write tool output and can't bundle turn-end
139	  // diffs without a working tree.
140	  //
141	  // Why fatal vs. fall-through to `git init`: a materialize failure means
142	  // the host either crashed mid-bundle, or its workspace plugin returned
143	  // a malformed response. Either is a strong signal something is wrong
144	  // upstream; falling through would silently desync the runner from the
145	  // host's view of the workspace lineage. Better to fail loud and let
146	  // the operator see the error.
147	  try {
148	    const matResp = (await client.call(
149	      'workspace.materialize',
150	      {},
151	    )) as WorkspaceMaterializeResponse;
152	    await materializeWorkspace({
153	      root: env.workspaceRoot,
154	      bundleBase64: matResp.bundleBytes,
155	    });
156	  } catch (err) {
157	    process.stderr.write(
158	      `runner: workspace.materialize failed: ${err instanceof Error ? err.message : String(err)}\n`,
159	    );
160	    await client.close();
161	    return 2;
162	  }
163	
164	  // Task 15 (Week 10–12): replay-at-boot. Fetch the persisted transcript
165	  // BEFORE constructing the SDK iterator so the model sees prior turns
166	  // before any live inbox message.
167	  //
168	  // Failure semantics: NON-FATAL. A storage hiccup or ACL drift here
169	  // shouldn't kill the chat — we'd rather hand the user a fresh
170	  // conversation than crash on resume. We log to stderr and continue
171	  // with an empty history.
172	  //
173	  // What we replay (and what we DON'T):
174	  //   - User turns and tool turns (tool_result blocks): yielded as
175	  //     SDKUserMessage. The SDK accepts a user message whose content is
176	  //     either a string or an Anthropic-compatible content-block array;
177	  //     we use the array form so tool_result blocks round-trip.
178	  //   - Assistant turns: NOT re-yielded. The SDK's prompt iterator only
179	  //     accepts user-shaped messages; injecting prior assistant text
180	  //     would require either the SDK's `resume(sessionId)` (we don't
181	  //     track its internal session id across runner restarts) or a
182	  //     `setMessages` API that doesn't exist today. The model regenerates
183	  //     from the user-side context. This re-spends LLM tokens but is
184	  //     simple and correct — the model has full context for a coherent
185	  //     continuation. (Future optimization: pursue resume(sessionId).)
186	  let replayTurns: ConversationFetchHistoryTurn[] = [];
187	  if (conversationId !== null) {
188	    try {
189	      const resp = (await client.call('conversation.fetch-history', {
190	        conversationId,
191	      })) as ConversationFetchHistoryResponse;
192	      replayTurns = resp.turns;
193	    } catch (err) {
194	      process.stderr.write(
195	        `runner: conversation.fetch-history failed: ${err instanceof Error ? err.message : String(err)}\n`,
196	      );
197	      replayTurns = [];
198	    }
199	  }
200	
201	  let tools;
202	  try {
203	    tools = ((await client.call('tool.list', {})) as ToolListResponse).tools;
204	  } catch (err) {
205	    process.stderr.write(
206	      `runner: tool.list failed: ${err instanceof Error ? err.message : String(err)}\n`,
207	    );
208	    await client.close();
209	    return 2;
210	  }
211	
212	  // Defensive client-side filter against agentConfig.allowedTools when it
213	  // is non-empty. An empty allow-list means "no per-agent restriction"
214	  // (orchestrator default); a non-empty list overrides what the host
215	  // returned. This is belt-and-suspenders against the dispatcher filter
216	  // (Task 7) — if either the host or runner mis-orders a refactor, the
217	  // tool catalog the SDK sees is still bounded.
218	  if (agentConfig.allowedTools.length > 0) {
219	    const allow = new Set(agentConfig.allowedTools);
220	    tools = tools.filter((t) => allow.has(t.name));
221	  }
222	
223	  const hostMcpServer = createHostMcpServer({ client, tools });
224	  const inbox = createInboxLoop({ client });
225	  // Phase 3: workspace commits are turn-end via git-status against
226	  // /permanent (`commitTurnAndBundle` at the SDK `result` boundary).
227	  // The legacy PostToolUse-based diff accumulator is gone — git status
228	  // catches ALL writes regardless of tool, including the Bash deletes
229	  // and MCP writes the legacy path missed.
230	
231	  // Tracks the last accepted workspace version so the host's optimistic-
232	  // concurrency check sees a coherent lineage across turns.
233	  let parentVersion: string | null = null;
234	  // Host-side bookkeeping for the final event.chat-end outcome. The SDK
235	  // maintains its OWN transcript internally; this array is only the shape
236	  // the host cares about (user/assistant text round-tripped through
237	  // AgentMessage). NOT the same as `replayTurns` above — replayTurns is
238	  // the persisted history we pull at boot to seed the SDK; chatEndHistory
239	  // is the within-process trace the host gets at chat:end.
240	  const chatEndHistory: AgentMessage[] = [];
241	
242	  // Per-turn content-block accumulators. Drained at the SDK `result`
243	  // boundary into event.turn-end so @ax/conversations can persist the
244	  // turn (Task 3 of Week 10–12). We track assistant and tool turns
245	  // separately because they emit as distinct chat:turn-end events:
246	  //   - assistant: text + thinking + tool_use blocks observed in
247	  //     `assistant` SDK messages within the current turn.
248	  //   - tool: tool_result blocks observed in `user` SDK messages whose
249	  //     content is the SDK echoing the tool-result back into the
250	  //     transcript. Replay (Task 15) needs these to reconstruct the
251	  //     conversation; the user-side text the human typed already
252	  //     reaches the conversation table via POST /api/chat/messages
253	  //     (Task 9), so we deliberately skip plain-text user blocks here.
254	  let turnContentBlocks: ContentBlock[] = [];
255	  let turnToolResultBlocks: ContentBlock[] = [];
256	
257	  // Most-recent host-minted reqId from the inbox (J9). Set when a user
258	  // message arrives; read by `event.stream-chunk` emissions during the
259	  // assistant branch below. Lifetime is "from the inbox pull until the
260	  // next inbox pull" — chunks for the SAME reqId may continue across
261	  // multiple SDK `result` boundaries (the SDK may break a long response
262	  // into multiple turns), so we DO NOT clear this on turn-end. A chunk
263	  // that would emit before any user message has been pulled is impossible
264	  // by SDK construction (no input → no output), but we defend anyway:
265	  // an unset reqId causes the chunk to be skipped (no `event.stream-chunk`
266	  // with a missing reqId — the host's router can't route it).
267	  let currentReqId: string | undefined;
268	
269	  // Inbox → SDK user-message generator. Closing via `return` on cancel
270	  // tells the SDK no more user messages are coming, which lets the outer
271	  // `for await (msg of queryIter)` drain naturally and exit.
272	  //
273	  // Task 15 (Week 10–12): replay-at-boot. We yield prior user turns
274	  // (role=user with text content) BEFORE pulling from the live inbox.
275	  // Assistant AND tool turns are skipped — the model regenerates the
276	  // tool flow from the user-side context. We can't re-yield tool turns
277	  // standalone: Anthropic's API rejects (400 invalid_request_error) any
278	  // tool_result block that isn't paired with a tool_use in the
279	  // immediately preceding assistant message, and we don't have the
280	  // assistant turn (since the prompt iterator only accepts user-shaped
281	  // messages). Without the SDK's resume() API, replaying tool turns is
282	  // not safely possible. The conversation row still stores the tool
283	  // turn (Task 3's auto-append); on replay the SDK only sees user text
284	  // turns and the model regenerates tool flows from there.
285	  async function* userMessages(): AsyncGenerator<SDKUserMessage> {
286	    // ----- replay -----
287	    for (const turn of replayTurns) {
288	      if (turn.role === 'user') {
289	        // Collapse plain-text contentBlocks back into a string for the
290	        // SDK (matches the live-inbox shape so the model doesn't see a
291	        // mid-conversation format change). Multi-block user turns
292	        // (e.g. with images) yield the full block array.
293	        const allText = turn.contentBlocks.every(
294	          (b): b is TextBlock => b.type === 'text',
295	        );
296	        const content: SDKUserMessage['message']['content'] = allText
297	          ? turn.contentBlocks
298	              .map((b) => (b as TextBlock).text)
299	              .join('\n')
300	          : (turn.contentBlocks as unknown as SDKUserMessage['message']['content']);
301	        yield {
302	          type: 'user',
303	          parent_tool_use_id: null,
304	          message: { role: 'user', content },
305	        };
306	      } else {
307	        // assistant + tool turns are NOT re-yielded; the model
308	        // regenerates from the user-side context. Tool turns
309	        // specifically can't be yielded standalone (Anthropic 400:
310	        // tool_result without paired tool_use in the immediately
311	        // preceding assistant message).
312	        process.stderr.write(
313	          `runner: skipping replay of role=${turn.role} turn (model will regenerate from user-side context)\n`,
314	        );
315	      }
316	    }
317	    // ----- live inbox -----
318	    for (;;) {
319	      const entry = await inbox.next();
320	      if (entry.type === 'cancel') return;
321	      if (entry.payload === undefined) continue;
322	      // Capture the host-minted reqId so subsequent stream-chunk
323	      // emissions correlate back to the originating request. Both fields
324	      // are set on `user-message` entries by the InboxLoop layer.
325	      if (typeof entry.reqId === 'string' && entry.reqId.length > 0) {
326	        currentReqId = entry.reqId;
327	      }
328	      chatEndHistory.push({ role: 'user', content: entry.payload.content });
329	      yield {
330	        type: 'user',
331	        parent_tool_use_id: null,
332	        message: { role: 'user', content: entry.payload.content },
333	      };
334	    }
335	  }
336	
337	  let exitCode = 0;
338	  let terminatedReason: string | undefined;
339	  let terminatedError:
340	    | { name: string; message: string; stack?: string }
341	    | undefined;
342	
343	  try {
344	    const queryIter = query({
345	      prompt: userMessages(),
346	      options: {
347	        // ANTHROPIC_API_KEY is the `ax-cred:<hex>` placeholder (substituted
348	        // by the credential-proxy mid-flight); no ANTHROPIC_BASE_URL — SDK
349	        // calls api.anthropic.com directly through HTTPS_PROXY.
350	        env: proxyStartup.anthropicEnv,
351	        cwd: env.workspaceRoot,
352	        disallowedTools: [...DISABLED_BUILTINS],
353	        // canUseTool stays as a belt-and-suspenders allow-path. The real
354	        // pre-call hook-bus forwarding happens in the PreToolUse hook below,
355	        // which ALWAYS fires (canUseTool only fires when the CLI decides a
356	        // tool needs a permission prompt — built-ins like Bash with benign
357	        // input don't reach it). See pre-tool-use.ts for the rationale.
358	        canUseTool: createCanUseTool({ client }),
359	        hooks: {
360	          PreToolUse: [{ hooks: [createPreToolUseHook({ client })] }],
361	          PostToolUse: [
362	            {
363	              hooks: [
364	                createPostToolUseHook({ client }),
365	              ],
366	            },
367	          ],
368	        },
369	        mcpServers: { [MCP_HOST_SERVER_NAME]: hostMcpServer },
370	        // Empty settingSources = SDK isolation mode: the runner does NOT
371	        // read ~/.claude, project settings, or CLAUDE.md. Config for this
372	        // sandbox arrives entirely through host-mediated IPC.
373	        settingSources: [],
374	        // Week 9.5: use the frozen agentConfig.systemPrompt the host wrote
375	        // at session-creation time. An empty string falls back to the SDK
376	        // preset (the dev-agents-stub seeds a default; production agents
377	        // require non-empty by validation). systemPrompt is USER-AUTHORED
378	        // and intended for the LLM — not interpolated into shell, paths,
379	        // or HTML.
380	        systemPrompt:
381	          agentConfig.systemPrompt.length > 0
382	            ? agentConfig.systemPrompt
383	            : { type: 'preset', preset: 'claude_code' },
384	      },
385	    });
386	
387	    for await (const msg of queryIter) {
388	      if (msg.type === 'assistant') {
389	        const assistant: SDKAssistantMessage = msg;
390	        // Only plain text blocks round-trip into host history. Tool-use
391	        // blocks stay inside the SDK's session — the host observes tool
392	        // activity via event.tool-post-call, not via the transcript.
393	        const text = assistant.message.content
394	          .flatMap((block) => (block.type === 'text' ? [block.text] : []))
395	          .join('\n');
396	        if (text.length > 0) {
397	          chatEndHistory.push({ role: 'assistant', content: text });
398	        }
399	        // Accumulate full ContentBlock[] for the per-turn transcript that
400	        // ships to @ax/conversations via event.turn-end. Every block kind
401	        // ContentBlockSchema knows about is mapped explicitly:
402	        //   - text / thinking / redacted_thinking / tool_use
403	        //
404	        // Replay (Task 15) requires Anthropic-compatibility (J3): a
405	        // missing redacted_thinking block leaves a hole the model can
406	        // detect on a follow-up turn, so we MUST preserve it verbatim.
407	        // Unknown block kinds are dropped defensively so a future SDK
408	        // addition can't bypass the canonical schema.
409	        for (const block of assistant.message.content) {
410	          if (block.type === 'text') {
411	            turnContentBlocks.push({ type: 'text', text: block.text });
412	            // Per-block streaming (Task 6 / J9). The SDK delivers text
413	            // blocks as the model produces them; we forward each as a
414	            // `event.stream-chunk` so the host's chat:stream-chunk
415	            // subscriber (Task 5) can fan out to waiting clients (Task
416	            // 7). Empty-text blocks are skipped — emitting `{ text: '' }`
417	            // chunks is noise. Failure is non-fatal: the host may be
418	            // tearing down, and the canonical transcript still flows
419	            // via event.turn-end / event.chat-end. Untrusted (J2):
420	            // `block.text` is model output and reaches the host
421	            // verbatim — host-side renderers sanitize.
422	            if (currentReqId !== undefined && block.text.length > 0) {
423	              await client
424	                .event('event.stream-chunk', {
425	                  reqId: currentReqId,
426	                  text: block.text,
427	                  kind: 'text',
428	                })
429	                .catch(() => {
430	                  /* host may be tearing down; non-fatal */
431	                });
432	            }
433	          } else if (block.type === 'thinking') {
434	            turnContentBlocks.push({
435	              type: 'thinking',
436	              thinking: block.thinking,
437	              ...(typeof block.signature === 'string'
438	                ? { signature: block.signature }
439	                : {}),
440	            });
441	            // Same per-block streaming for thinking. The host's UI
442	            // toggles thinking visibility (Task 21 / J4), but the
443	            // chunk still travels with `kind: 'thinking'` so a
444	            // subscriber can route it to the right pane.
445	            if (currentReqId !== undefined && block.thinking.length > 0) {
446	              await client
447	                .event('event.stream-chunk', {
448	                  reqId: currentReqId,
449	                  text: block.thinking,
450	                  kind: 'thinking',
451	                })
452	                .catch(() => {
453	                  /* host may be tearing down; non-fatal */
454	                });
455	            }
456	          } else if (block.type === 'redacted_thinking') {
457	            // Redacted-thinking blocks have no human-readable text — the
458	            // model returned an opaque blob. We persist it (J3 — the
459	            // SDK detects holes on follow-up turns) but DO NOT emit a
460	            // stream chunk: there's nothing to render, and `kind`
461	            // wouldn't accept it anyway.
462	            turnContentBlocks.push({
463	              type: 'redacted_thinking',
464	              data: (block as { data: string }).data,
465	            });
466	          } else if (block.type === 'tool_use') {
467	            // Tool-use blocks are observed via event.tool-post-call
468	            // (when the tool actually runs) and persisted at turn-end.
469	            // They are not streamed text and have no `kind` mapping.
470	            turnContentBlocks.push({
471	              type: 'tool_use',
472	              id: block.id,
473	              name: block.name,
474	              input: (block.input ?? {}) as Record<string, unknown>,
475	            });
476	          }
477	        }
478	      } else if (msg.type === 'user') {
479	        // The SDK echoes tool_result blocks back as `user` messages once
480	        // a tool finishes (the model issued a tool_use; the runner ran
481	        // the tool; the SDK threads the result into the transcript as a
482	        // user turn so the next assistant turn can see it). Replay
483	        // depends on these landing in the conversation row. Plain-text
484	        // user content is NOT collected: the human's typed message
485	        // arrives via POST /api/chat/messages (Task 9), and tool_result
486	        // blocks are the only thing the runner is the authoritative
487	        // source for here.
488	        const userMsg = msg as { message?: { content?: unknown } };
489	        const content = userMsg.message?.content;
490	        if (Array.isArray(content)) {
491	          for (const block of content as Array<{ type?: string }>) {
492	            if (block.type === 'tool_result') {
493	              const tr = block as {
494	                type: 'tool_result';
495	                tool_use_id?: string;
496	                content?: unknown;
497	                is_error?: boolean;
498	              };
499	              if (typeof tr.tool_use_id === 'string') {
500	                // Narrow array content to the text/image subset per
501	                // ToolResultBlockSchema (`string | (TextBlock |
502	                // ImageBlock)[]`). Image entries MUST round-trip — a
503	                // tool that returns image content (screenshot tool, Read
504	                // on a binary, etc.) loses context on replay otherwise.
505	                // Other entry types are dropped defensively so a future
506	                // SDK shape doesn't silently bypass the canonical schema.
507	                let normalizedContent: string | Array<TextBlock | ImageBlock> =
508	                  '';
509	                if (typeof tr.content === 'string') {
510	                  normalizedContent = tr.content;
511	                } else if (Array.isArray(tr.content)) {
512	                  const narrowed: Array<TextBlock | ImageBlock> = [];
513	                  for (const item of tr.content as Array<{
514	                    type?: string;
515	                    text?: unknown;
516	                    source?: unknown;
517	                  }>) {
518	                    if (item.type === 'text' && typeof item.text === 'string') {
519	                      narrowed.push({ type: 'text', text: item.text });
520	                    } else if (
521	                      item.type === 'image' &&
522	                      item.source !== undefined
523	                    ) {
524	                      // The SDK's image-block shape matches ImageBlock
525	                      // already; the .source discriminated-union is
526	                      // validated at the storage boundary by
527	                      // ContentBlockSchema, so no further narrowing here.
528	                      narrowed.push(item as unknown as ImageBlock);
529	                    }
530	                  }
531	                  normalizedContent = narrowed;
532	                }
533	                const normalized: ContentBlock = {
534	                  type: 'tool_result',
535	                  tool_use_id: tr.tool_use_id,
536	                  content: normalizedContent,
537	                  ...(typeof tr.is_error === 'boolean'
538	                    ? { is_error: tr.is_error }
539	                    : {}),
540	                };
541	                turnToolResultBlocks.push(normalized);
542	              }
543	            }
544	          }
545	        }
546	      } else if (msg.type === 'result') {
547	        // Turn boundary (Phase 3). Replaces the legacy PostToolUse-based
548	        // diff observer with `git status` + bundle:
549	        //   1. Stage everything in /permanent (`git add -A`) — catches
550	        //      ALL writes, regardless of which tool wrote (Bash, MCP,
551	        //      SDK Write/Edit/MultiEdit, raw fs, jsonl). Closes the
552	        //      Bash-delete + MCP-write + jsonl gaps that motivated
553	        //      the redesign.
554	        //   2. If nothing's staged → empty turn → skip commit-notify
555	        //      entirely (same heartbeat-only semantic the legacy path
556	        //      had for empty diffs).
557	        //   3. Otherwise: commit, build a thin `baseline..main` bundle,
558	        //      ship as `workspace.commit-notify`.
559	        //   4. On accept: advance refs/heads/baseline so the next turn
560	        //      bundles from the new state.
561	        //   5. On veto: roll the working tree back to baseline (the
562	        //      agent's writes for this turn are undone).
563	        //   6. On IPC error (host unreachable, 5xx): preserve the
564	        //      working tree as-is. Don't advance baseline; don't
565	        //      rollback. The next turn's `git add -A` will accumulate
566	        //      this turn's changes plus the next turn's, and we ship
567	        //      the combined bundle. Best-effort retry by accumulation.
568	        //
569	        // Failures here MUST NOT terminate the chat — `event.turn-end`
570	        // is still the heartbeat the host keys off.
571	        try {
572	          const bundleB64 = await commitTurnAndBundle({
573	            root: env.workspaceRoot,
574	            reason: 'turn',
575	          });
576	          if (bundleB64 !== null) {
577	            try {
578	              const resp = (await client.call('workspace.commit-notify', {
579	                parentVersion,
580	                reason: 'turn',
581	                bundleBytes: bundleB64,
582	              })) as WorkspaceCommitNotifyResponse;
583	              if (resp.accepted) {
584	                parentVersion = resp.version as unknown as string;
585	                await advanceBaseline(env.workspaceRoot);
586	              } else {
587	                // Host vetoed — surface to stderr (the host's log sink)
588	                // and rollback so the agent's next turn starts clean.
589	                process.stderr.write(
590	                  `runner: workspace rejected: ${resp.reason}\n`,
591	                );
592	                await rollbackToBaseline(env.workspaceRoot);
593	              }
594	            } catch (err) {
595	              // Network / 5xx / timeout: keep the working tree intact
596	              // so the next turn's accumulated changes flow as one
597	              // bundle. Don't advance baseline; don't rollback. Same
598	              // trade-off the legacy accumulator path made.
599	              process.stderr.write(
600	                `runner: commit-notify failed: ${err instanceof Error ? err.message : String(err)}\n`,
601	              );
602	            }
603	          }
604	        } catch (err) {
605	          // commitTurnAndBundle itself failed (git binary missing,
606	          // /permanent in a weird state, etc.). Non-fatal; the next
607	          // turn will retry.
608	          process.stderr.write(
609	            `runner: commitTurnAndBundle failed: ${err instanceof Error ? err.message : String(err)}\n`,
610	          );
611	        }
612	
613	        // One turn of assistant output finished. The SDK now awaits the
614	        // next yield from userMessages() — i.e. the next inbox pull.
615	        //
616	        // We may emit up to TWO chat:turn-end events at this boundary:
617	        //   1. role='tool' if the runner observed any tool_result blocks
618	        //      during this turn (the SDK echoed them back as user msgs).
619	        //      Emitted FIRST because they chronologically precede the
620	        //      assistant's wrap-up text in the transcript.
621	        //   2. role='assistant' for the assistant turn itself. Emitted
622	        //      unconditionally as a heartbeat — contentBlocks is only
623	        //      attached when non-empty so empty turns stay heartbeats.
624	        //
625	        // Failures here MUST NOT terminate the chat (host may be tearing
626	        // down). Each call swallows independently.
627	        if (turnToolResultBlocks.length > 0) {
628	          const toolBlocks = turnToolResultBlocks;
629	          turnToolResultBlocks = [];
630	          await client
631	            .event('event.turn-end', {
632	              reason: 'user-message-wait',
633	              role: 'tool',
634	              contentBlocks: toolBlocks,
635	            })
636	            .catch(() => {
637	              /* host may be tearing down; non-fatal */
638	            });
639	        }
640	
641	        const assistantBlocks = turnContentBlocks;
642	        turnContentBlocks = [];
643	        await client
644	          .event('event.turn-end', {
645	            reason: 'user-message-wait',
646	            role: 'assistant',
647	            ...(assistantBlocks.length > 0
648	              ? { contentBlocks: assistantBlocks }
649	              : {}),
650	          })
651	          .catch(() => {
652	            /* host may be tearing down; non-fatal */
653	          });
654	      }
655	      // system / partial / progress / etc. are SDK bookkeeping —
656	      // the host doesn't need to see them. (`user` messages ARE handled
657	      // above, but only to extract tool_result blocks for replay.)
658	    }
659	  } catch (err) {
660	    exitCode = 1;
661	    if (err instanceof Error) {
662	      terminatedReason = `${err.name}: ${err.message}`;
663	      terminatedError = {
664	        name: err.name,
665	        message: err.message,
666	        ...(err.stack !== undefined ? { stack: err.stack } : {}),
667	      };
668	    } else {
669	      terminatedReason = String(err);
670	      terminatedError = { name: 'NonError', message: String(err) };
671	    }
672	  }
673	
674	  // Single event.chat-end at the end of the runner's life, awaited so the
675	  // event reaches the wire before the process exits. If the host is
676	  // already gone, swallow — there's nothing left to signal to. The
677	  // `error` shape here is a plain object so the event payload survives
678	  // JSON.stringify (an `Error` instance would serialize to `{}`, stripping
679	  // the diagnostic).
680	  const outcome =
681	    exitCode === 0
682	      ? { kind: 'complete' as const, messages: chatEndHistory }
683	      : {
684	          kind: 'terminated' as const,
685	          reason: terminatedReason ?? 'unknown',
686	          ...(terminatedError !== undefined ? { error: terminatedError } : {}),
687	        };
688	  await client.event('event.chat-end', { outcome }).catch(() => {
689	    /* swallow */
690	  });
691	  await client.close().catch(() => {
692	    /* close is best-effort; a clean chat shouldn't exit non-zero on teardown */
693	  });
694	  // Stop the credential-proxy bridge (k8s mode) so its TCP port and active
695	  // sockets are released before the runner exits. Best-effort: any failure
696	  // here shouldn't change the exit code — the chat already emitted its
697	  // outcome.
698	  if (proxyStartup.stop !== undefined) {
699	    try {
700	      proxyStartup.stop();
701	    } catch {
702	      /* swallow */
703	    }
704	  }
705	  return exitCode;
706	}
707	
708	// ESM main-module guard. `require.main === module` doesn't work in ESM.
709	// Compare URLs to detect "was this file invoked directly".
710	if (
711	  process.argv[1] !== undefined &&
712	  import.meta.url === pathToFileURL(process.argv[1]).href
713	) {
714	  main()
715	    .then((code) => process.exit(code))
716	    .catch((err: unknown) => {
717	      process.stderr.write(
718	        `runner: fatal: ${err instanceof Error ? err.message : String(err)}\n`,
719	      );
720	      process.exit(2);
721	    });
722	}
